// frontend/src/components/Auth/Register.js
import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton,
  Tooltip,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Card,
  CardContent,
  Grid,
  Chip
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Person,
  Email,
  Lock,
  VpnKey,
  Security,
  Check,
  Close,
  Info,
  Key,
  AccountBalance,
  Payment,
  Subscriptions
} from '@mui/icons-material';
import { Link as RouterLink, useNavigate, useLocation } from 'react-router-dom';
import { toast } from 'react-toastify';
import authService from '../../services/authService';

const INVITE_CODE_VALUE = "Raikamaster202021@"; // Store the invite code value

// Opções de recarga para novos usuários
const rechargeOptions = [
  { value: 'R$ 9', link: 'https://pay.hub.la/ekfJp2uXQ0S5ZBb65Otb', isTest: true },
  { value: 'R$ 50', link: 'https://pay.hub.la/MdORdaFcTzWvhT9IkZHP' },
  { value: 'R$ 100', link: 'https://pay.hub.la/mFfwQbUAqILTw8bfDXjo' },
  { value: 'R$ 200', link: 'https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC' },
  { value: 'R$ 500', link: 'https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z' }
];

const Register = () => {
  const navigate = useNavigate();
  const location = useLocation(); // Get location to access URL parameters

  const [formData, setFormData] = useState({
    full_name: '',
    email: '',
    password: '',
    confirmPassword: '',
    bitget_api_key: '',
    bitget_api_secret: '',
    bitget_passphrase: '',
    invite_code: '' // Novo campo para o código de convite
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [showApiSecret, setShowApiSecret] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [passwordValidation, setPasswordValidation] = useState({
    length: false,
    uppercase: false,
    lowercase: false,
    number: false,
    special: false
  });

  const [hasPaymentAccess, setHasPaymentAccess] = useState(false);
  // eslint-disable-next-line no-unused-vars
  const [inviteCodeUsed, setInviteCodeUsed] = useState(false); // Novo estado para código de convite
  const [inviteCodeScreenVisible, setInviteCodeScreenVisible] = useState(false);
  const [inviteCodeAttempt, setInviteCodeAttempt] = useState('');
  const [inviteCodeVerified, setInviteCodeVerified] = useState(false);

  // Verificar se há parâmetro de acesso na URL (vindo do webhook do Hubla)
  React.useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const accessToken = urlParams.get('access_token');
    const paymentConfirmed = urlParams.get('payment_confirmed');
    const source = urlParams.get('source');

    if (source === 'invite') {
      setInviteCodeScreenVisible(true);
    } else {
      setInviteCodeScreenVisible(false); // Default to false if not from invite link
    }

    if (accessToken && paymentConfirmed === 'true') {
      validateAccessToken(accessToken);
      setInviteCodeScreenVisible(false); // Payment confirmed, show full form
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, [location.search]);

  const validateAccessToken = async (token) => {
    try {
      const response = await fetch('/api/hubla/validate-token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ access_token: token }),
      });

      const data = await response.json();

      if (data.valid) {
        setHasPaymentAccess(true);
        // Opcional: pré-preencher o email se disponível
        if (data.email) {
          setFormData(prev => ({ ...prev, email: data.email }));
        }
        toast.success('Pagamento confirmado! Você pode prosseguir com o cadastro.');
      } else {
        setError(data.error || 'Token de acesso inválido');
        toast.error('Token de acesso inválido ou expirado');
      }
    } catch (error) {
      console.error('Erro ao validar token:', error);
      setError('Erro ao validar acesso. Tente novamente.');
      toast.error('Erro ao validar acesso');
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name === 'inviteCodeAttempt') {
      setInviteCodeAttempt(value);
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }

    if (name === 'password') {
      validatePassword(value);
    }

    // Não limpar o erro automaticamente - deixar o usuário ver a mensagem
  };

  const validatePassword = (password) => {
    setPasswordValidation({
      length: password.length >= 8,
      uppercase: /[A-Z]/.test(password),
      lowercase: /[a-z]/.test(password),
      number: /\d/.test(password),
      // eslint-disable-next-line no-useless-escape
      special: /[@$!%*?&_\-]/.test(password)
    });
  };

  const isPasswordValid = () => {
    return Object.values(passwordValidation).every(Boolean);
  };

  const handleInviteCodeVerification = () => {
    setError('');
    if (inviteCodeAttempt === INVITE_CODE_VALUE) {
      setInviteCodeVerified(true);
      setInviteCodeUsed(true);
      setFormData(prev => ({ ...prev, invite_code: inviteCodeAttempt }));
      toast.success('✅ Código de convite válido! Prossiga com o cadastro.', {
        autoClose: 5000,
        position: "top-center"
      });
    } else {
      const errorMsg = '❌ Código de convite inválido. Verifique se digitou corretamente.';
      setError(errorMsg);
      toast.error(errorMsg, {
        autoClose: 6000,
        position: "top-center"
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (!hasPaymentAccess && !inviteCodeVerified) { // Check inviteCodeVerified instead of formData.invite_code
      setError('Acesso negado. Você precisa efetuar o pagamento ou inserir um código de convite válido para se cadastrar.');
      setLoading(false);
      return;
    }

    const { full_name, email, password, confirmPassword, bitget_api_key, bitget_api_secret, bitget_passphrase } = formData;

    // Include invite_code in validation if it was verified
    const requiredFields = [full_name, email, password, confirmPassword, bitget_api_key, bitget_api_secret, bitget_passphrase];
    if (requiredFields.some(field => !field)) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    if (!authService.validateEmail(email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    if (!isPasswordValid()) {
      setError('A senha não atende aos requisitos de complexidade');
      setLoading(false);
      return;
    }

    if (password !== confirmPassword) {
      setError('As senhas não coincidem');
      setLoading(false);
      return;
    }

    try {
      const registrationData = {
        full_name,
        email,
        password,
        bitget_api_key,
        bitget_api_secret,
        bitget_passphrase,
        invite_code: formData.invite_code || undefined // Envia o código de convite se existir
      };

      const response = await authService.register(registrationData);

      if (response && response.invite_code_used) {
        setInviteCodeUsed(true);
        toast.success('Conta criada com sucesso com código de convite! Faça login para continuar.');
      } else {
        toast.success('Conta criada com sucesso! Faça login para continuar.');
      }
      navigate('/login');
    } catch (error) {
      console.error('Erro no registro:', error);

      // Melhorar as mensagens de erro baseadas no tipo de erro
      let errorMessage = '';

      if (error.message.includes('Apikey does not exist') || error.message.includes('API')) {
        errorMessage = '❌ Credenciais da API Bitget inválidas. Verifique se sua API Key, Secret e Passphrase estão corretos e se a API está ativa na Bitget.';
      } else if (error.message.includes('email')) {
        errorMessage = '❌ Este email já está cadastrado. Tente fazer login ou use outro email.';
      } else if (error.message.includes('network') || error.message.includes('fetch')) {
        errorMessage = '❌ Erro de conexão. Verifique sua internet e tente novamente.';
      } else {
        errorMessage = `❌ Erro ao criar conta: ${error.message || 'Tente novamente em alguns instantes.'}`;
      }

      setError(errorMessage);
      toast.error(errorMessage, {
        autoClose: 8000, // 8 segundos para dar tempo de ler
        position: "top-center"
      });
    } finally {
      setLoading(false);
    }
  };

  const ValidationIcon = ({ isValid }) => (
    isValid ? <Check sx={{ color: '#C0C0C0', fontSize: 16 }} /> : <Close sx={{ color: '#C0C0C0', fontSize: 16 }} />
  );

  return (
    <Container maxWidth="md">
      <Box
        sx={{
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          py: 4
        }}
      >
        <Paper
          elevation={8}
          sx={{
            p: 4,
            width: '100%',
            maxWidth: 600,
            background: 'rgba(0, 0, 0, 0.7)',
            border: '1px solid rgba(192, 192, 192, 0.3)',
            borderRadius: 2
          }}
        >
          {/* Logo/Título */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography
              variant="h4"
              component="h1"
              sx={{
                fontWeight: 'bold',
                color: '#C0C0C0',
                mb: 1
              }}
            >
              Nautilus Automação
            </Typography>
            <Typography
              variant="subtitle1"
              sx={{ color: '#C0C0C0', mb: 2 }}
            >
              Crie sua conta de trading
            </Typography>

            {/* Card de Recarga/Assinatura para Novos Usuários */}
            {!hasPaymentAccess && !inviteCodeVerified && (
              <Card sx={{ 
                mb: 3, 
                background: 'rgba(0, 0, 0, 0.7)',
                border: '1px solid rgba(192, 192, 192, 0.3)',
                borderRadius: 2
              }}>
                <CardContent>
                  <Typography variant="body2" sx={{ color: '#C0C0C0', mb: 2, textAlign: 'center', fontWeight: 500 }}>
                    Escolha entre recarregar sua conta ou assinar mensalmente para continuar.
                  </Typography>

                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                    <Subscriptions sx={{ color: '#C0C0C0', mr: 1 }} />
                    <Typography variant="h6" sx={{ color: '#C0C0C0', fontWeight: 'bold' }}>
                      Assinatura
                    </Typography>
                  </Box>

                  {/* Botão de Assinatura */}
                  <Button
                    fullWidth
                    variant="contained"
                    href="https://pay.hub.la/tmF5YtOlGb1GDVFSam7S"
                    target="_blank"
                    sx={{
                      mb: 3,
                      background: 'rgba(0, 0, 0, 0.8)',
                      border: '1px solid rgba(192, 192, 192, 0.3)',
                      color: '#C0C0C0',
                      fontWeight: 'bold',
                      py: 1.5,
                      '&:hover': {
                        background: 'rgba(0, 0, 0, 0.9)',
                        border: '1px solid #C0C0C0'
                      }
                    }}
                    startIcon={<Subscriptions sx={{ color: '#C0C0C0' }} />}
                  >
                    🔥 ASSINATURA MENSAL - R$ 299,99/mês
                  </Button>

                  {/* Seção de Recarga */}
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                    <AccountBalance sx={{ color: '#C0C0C0', mr: 1 }} />
                    <Typography variant="h6" sx={{ color: '#C0C0C0', fontWeight: 'bold' }}>
                      Recarregar (Não necessita assinatura)
                    </Typography>
                  </Box>

                  <Grid container spacing={1}>
                    {rechargeOptions.map((option, index) => (
                      <Grid item xs={6} sm={4} key={index}>
                        <Button
                          fullWidth
                          variant="outlined"
                          href={option.link}
                          target="_blank"
                          sx={{
                            color: '#C0C0C0',
                            borderColor: 'rgba(192, 192, 192, 0.5)',
                            background: 'rgba(0, 0, 0, 0.3)',
                            '&:hover': {
                              backgroundColor: 'rgba(0, 0, 0, 0.6)',
                              borderColor: '#C0C0C0'
                            },
                            fontSize: '0.875rem',
                            py: 1
                          }}
                          startIcon={<Payment sx={{ color: '#C0C0C0' }} />}
                        >
                          {option.value}
                          {option.isTest && (
                            <Chip
                              label="TESTE"
                              size="small"
                              sx={{
                                ml: 0.5,
                                height: 16,
                                fontSize: '0.6rem',
                                backgroundColor: 'rgba(192, 192, 192, 0.8)',
                                color: '#000'
                              }}
                            />
                          )}
                        </Button>
                      </Grid>
                    ))}
                  </Grid>
                </CardContent>
              </Card>
            )}

            {/* Status de Acesso - Conditionally render based on invite flow */}
            {(!inviteCodeScreenVisible || inviteCodeVerified) && (
              hasPaymentAccess ? (
                <Alert severity="success" sx={{ mb: 2, backgroundColor: 'rgba(0, 0, 0, 0.6)', color: '#C0C0C0', border: '1px solid rgba(192, 192, 192, 0.3)' }}>
                  ✅ Pagamento confirmado! Você pode prosseguir com o cadastro.
                </Alert>
              ) : !inviteCodeVerified && (
                <Alert severity="warning" sx={{ mb: 2, backgroundColor: 'rgba(0, 0, 0, 0.6)', color: '#C0C0C0', border: '1px solid rgba(192, 192, 192, 0.3)' }}>
                  ⚠️ Acesso restrito: É necessário efetuar o pagamento antes de se cadastrar.
                  <br />
                  <Link component={RouterLink} to="/login" sx={{ color: '#C0C0C0', fontWeight: 'bold', textDecoration: 'underline' }}>
                    Voltar para o login e efetuar pagamento
                  </Link>
                </Alert>
              )
            )}
          </Box>

          {/* Invite Code Input Section */}
          {inviteCodeScreenVisible && !inviteCodeVerified && (
            <Box sx={{ mb: 3 }}>
              <Typography variant="h6" sx={{ mb: 1, textAlign: 'center', color: '#C0C0C0' }}>
                Registrar com Código de Convite
              </Typography>
              <TextField
                fullWidth
                name="inviteCodeAttempt"
                label="Digite o Código de Convite"
                value={inviteCodeAttempt}
                onChange={handleChange}
                margin="normal"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Key sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />
              <Button
                fullWidth
                variant="contained"
                onClick={handleInviteCodeVerification}
                sx={{ 
                  mt: 2,
                  background: 'rgba(0, 0, 0, 0.8)',
                  border: '1px solid rgba(192, 192, 192, 0.3)',
                  color: '#C0C0C0',
                  '&:hover': {
                    background: 'rgba(0, 0, 0, 0.9)',
                    border: '1px solid #C0C0C0'
                  }
                }}
                disabled={loading || !inviteCodeAttempt}
              >
                Verificar Código
              </Button>
              {error && inviteCodeScreenVisible && !inviteCodeVerified && (
                <Alert 
                  severity="error" 
                  sx={{ 
                    mt: 2,
                    backgroundColor: 'rgba(211, 47, 47, 0.15)',
                    color: '#ff6b6b',
                    border: '2px solid rgba(211, 47, 47, 0.5)',
                    borderRadius: 2,
                    fontWeight: 'bold',
                    '& .MuiAlert-icon': {
                      color: '#ff6b6b'
                    }
                  }}
                  onClose={() => setError('')}
                >
                  {error}
                </Alert>
              )}
               <Typography variant="body2" sx={{ mt: 2, textAlign: 'center', color: '#C0C0C0' }}>
                Já tem uma conta ou quer pagar?{' '}
                <Link component={RouterLink} to="/login" sx={{ color: '#C0C0C0', fontWeight: 'bold', textDecoration: 'underline' }}>
                  Voltar para o Login
                </Link>
              </Typography>
            </Box>
          )}

          {/* Formulário Principal - Conditionally render */}
          {(!inviteCodeScreenVisible || inviteCodeVerified) && (
            <Box component="form" onSubmit={handleSubmit}>
              {error && (!inviteCodeScreenVisible || inviteCodeVerified) && (
                <Alert 
                  severity="error" 
                  sx={{ 
                    mb: 3,
                    backgroundColor: 'rgba(211, 47, 47, 0.15)',
                    color: '#ff6b6b',
                    border: '2px solid rgba(211, 47, 47, 0.5)',
                    borderRadius: 2,
                    fontWeight: 'bold',
                    '& .MuiAlert-icon': {
                      color: '#ff6b6b'
                    },
                    '& .MuiAlert-message': {
                      fontSize: '0.95rem',
                      lineHeight: 1.5
                    }
                  }}
                  onClose={() => setError('')}
                >
                  {error}
                </Alert>
              )}

              {/* Nome Completo */}
              <TextField
                fullWidth
                name="full_name"
                label="Nome Completo"
                value={formData.full_name}
                onChange={handleChange}
                margin="normal"
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Person sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* Email */}
              <TextField
                fullWidth
                name="email"
                label="Email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* Senha */}
              <TextField
                fullWidth
                name="password"
                label="Senha"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowPassword(!showPassword)}
                        edge="end"
                        sx={{ color: '#C0C0C0' }}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* Validação da senha */}
              {formData.password && (
                <Box sx={{ mt: 1, mb: 2 }}>
                  <Typography variant="caption" sx={{ color: '#C0C0C0', mb: 1, display: 'block' }}>
                    Requisitos da senha:
                  </Typography>
                  <List dense sx={{ py: 0 }}>
                    <ListItem sx={{ py: 0, px: 0 }}>
                      <ListItemIcon sx={{ minWidth: 24 }}>
                        <ValidationIcon isValid={passwordValidation.length} />
                      </ListItemIcon>
                      <ListItemText 
                        primary="Pelo menos 8 caracteres" 
                        primaryTypographyProps={{ variant: 'caption', sx: { color: '#C0C0C0' } }}
                      />
                    </ListItem>
                    <ListItem sx={{ py: 0, px: 0 }}>
                      <ListItemIcon sx={{ minWidth: 24 }}>
                        <ValidationIcon isValid={passwordValidation.uppercase} />
                      </ListItemIcon>
                      <ListItemText 
                        primary="Uma letra maiúscula" 
                        primaryTypographyProps={{ variant: 'caption', sx: { color: '#C0C0C0' } }}
                      />
                    </ListItem>
                    <ListItem sx={{ py: 0, px: 0 }}>
                      <ListItemIcon sx={{ minWidth: 24 }}>
                        <ValidationIcon isValid={passwordValidation.lowercase} />
                      </ListItemIcon>
                      <ListItemText 
                        primary="Uma letra minúscula" 
                        primaryTypographyProps={{ variant: 'caption', sx: { color: '#C0C0C0' } }}
                      />
                    </ListItem>
                    <ListItem sx={{ py: 0, px: 0 }}>
                      <ListItemIcon sx={{ minWidth: 24 }}>
                        <ValidationIcon isValid={passwordValidation.number} />
                      </ListItemIcon>
                      <ListItemText 
                        primary="Um número" 
                        primaryTypographyProps={{ variant: 'caption', sx: { color: '#C0C0C0' } }}
                      />
                    </ListItem>
                    <ListItem sx={{ py: 0, px: 0 }}>
                      <ListItemIcon sx={{ minWidth: 24 }}>
                        <ValidationIcon isValid={passwordValidation.special} />
                      </ListItemIcon>
                      <ListItemText 
                        primary="Um caractere especial (@$!%*?&_-)" 
                        primaryTypographyProps={{ variant: 'caption', sx: { color: '#C0C0C0' } }}
                      />
                    </ListItem>
                  </List>
                </Box>
              )}

              {/* Confirmar Senha */}
              <TextField
                fullWidth
                name="confirmPassword"
                label="Confirmar Senha"
                type={showConfirmPassword ? 'text' : 'password'}
                value={formData.confirmPassword}
                onChange={handleChange}
                margin="normal"
                required
                error={!!(formData.confirmPassword && formData.password !== formData.confirmPassword)}
                helperText={
                  formData.confirmPassword && formData.password !== formData.confirmPassword
                    ? 'As senhas não coincidem'
                    : ''
                }
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                        edge="end"
                        sx={{ color: '#C0C0C0' }}
                      >
                        {showConfirmPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* API Key da Bitget */}
              <TextField
                fullWidth
                name="bitget_api_key"
                label="Bitget API Key"
                value={formData.bitget_api_key}
                onChange={handleChange}
                margin="normal"
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <VpnKey sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <Tooltip title="Sua chave de API da Bitget para acessar dados de trading">
                        <Info sx={{ color: '#C0C0C0' }} />
                      </Tooltip>
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* API Secret da Bitget */}
              <TextField
                fullWidth
                name="bitget_api_secret"
                label="Bitget API Secret"
                type={showApiSecret ? 'text' : 'password'}
                value={formData.bitget_api_secret}
                onChange={handleChange}
                margin="normal"
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Security sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowApiSecret(!showApiSecret)}
                        edge="end"
                        sx={{ color: '#C0C0C0' }}
                      >
                        {showApiSecret ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* Passphrase da Bitget */}
              <TextField
                fullWidth
                name="bitget_passphrase"
                label="Bitget Passphrase"
                value={formData.bitget_passphrase}
                onChange={handleChange}
                margin="normal"
                required
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <Tooltip title="Passphrase da sua API Bitget (obrigatório para autenticação)">
                        <Info sx={{ color: '#C0C0C0' }} />
                      </Tooltip>
                    </InputAdornment>
                  ),
                  sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
                }}
                InputLabelProps={{
                  sx: { color: '#C0C0C0' }
                }}
                sx={{ '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
              />

              {/* Aviso de segurança */}
              <Alert severity="info" sx={{ mt: 2, mb: 2, backgroundColor: 'rgba(0, 0, 0, 0.6)', color: '#C0C0C0', border: '1px solid rgba(192, 192, 192, 0.3)' }}>
                <Typography variant="caption" sx={{ color: '#C0C0C0' }}>
                  🔒 Suas credenciais da API são criptografadas com AES-256 e armazenadas com segurança.
                  Nunca compartilhe suas chaves de API com terceiros.
                </Typography>
              </Alert>

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading || !isPasswordValid() || (!hasPaymentAccess && !inviteCodeVerified)}
                sx={{
                  mt: 3,
                  mb: 2,
                  py: 1.5,
                  fontSize: '1rem',
                  fontWeight: 'bold',
                  background: (hasPaymentAccess || inviteCodeVerified) ? 'rgba(0, 0, 0, 0.8)' : 'rgba(0, 0, 0, 0.3)',
                  border: (hasPaymentAccess || inviteCodeVerified) ? '1px solid rgba(192, 192, 192, 0.3)' : '1px solid rgba(192, 192, 192, 0.1)',
                  color: (hasPaymentAccess || inviteCodeVerified) ? '#C0C0C0' : 'rgba(192, 192, 192, 0.3)',
                  '&:hover': {
                    background: (hasPaymentAccess || inviteCodeVerified) ? 'rgba(0, 0, 0, 0.9)' : 'rgba(0, 0, 0, 0.3)',
                    border: (hasPaymentAccess || inviteCodeVerified) ? '1px solid #C0C0C0' : '1px solid rgba(192, 192, 192, 0.1)',
                  },
                  '&:disabled': {
                    background: 'rgba(0, 0, 0, 0.3)',
                    border: '1px solid rgba(192, 192, 192, 0.1)',
                    color: 'rgba(192, 192, 192, 0.3)'
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={24} sx={{ color: '#C0C0C0' }} />
                ) : (hasPaymentAccess || inviteCodeVerified) ? (
                  'Criar Conta'
                ) : (
                  'Pagamento Necessário'
                )}
              </Button>

              {/* Link para login */}
              <Box sx={{ textAlign: 'center', mt: 2 }}>
                <Typography variant="body2" sx={{ color: '#C0C0C0' }}>
                  Já tem uma conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/login"
                    sx={{
                      color: '#C0C0C0',
                      textDecoration: 'underline',
                      fontWeight: 'bold',
                      '&:hover': {
                        textDecoration: 'underline',
                      },
                    }}
                  >
                    Faça login
                  </Link>
                </Typography>
              </Box>
            </Box>
          )}
        </Paper>
      </Box>
    </Container>
  );
};

export default Register;
